import logo from '../logo.svg';

function Home() {

    function NotLoggedIn()
        {
        return [
            <> <form action="">
                    <label htmlFor="card-number">Card Number</label>
                    <input type='number' id="card-number" placeholder='0000 1111 2222 3333'/>
                </form>
                <button onClick={NotLoggedIn}>Sign In With a Differnet Card</button>
                </>
        ]
    }

    function LoggedIn(){
        return [
            <>
              <form action="">
                    <label htmlFor="card-number">Card Number</label>
                    <input type='number' id="card-number" placeholder='1111 2222 3333 4444'/>
                </form>
            </>
        ]
    }



    return (
        <>
        <div className='home-card'>
            <img src={logo} className="home-logo" alt="logo"  width={100}/>
            <h2>Sign on to CIBC Online Banking®</h2>
            <div className="alert-box">
               <p>Important notice: The way Personal and Business Banking clients sign on to online banking is changing. 
                <a href="/">Learn more </a> </p>
            </div>




            <div className="login-form">

              LoggedOut();


                  <button onClick={LoggedOut}>Sign in With A Different Card</button>
            </div>


          <div className="Home-btn">
            <button className="back-btn">Back</button>
            <button className="sign-in-btn">Continue</button>

          </div>

        <div className="extra-links">
            Not registered for online banking? <a href="/">Register Now</a>
            Trouble signing on? <a href="/">Reset your password</a>
        </div>



        </div>
        </>
    );
}

export default Home;
